import flask
import uuid
from flask import request, jsonify
from flask_cors import CORS


# instantiate the app
app = flask.Flask(__name__)
app.config["DEBUG"] = True

CORS(app)

# default index route: /
@app.route('/', methods=['GET'])
def hello():
    return 'Hello World!'

# create a custom route for posting new data from frontend
@app.route('/api/v1/add', methods=['POST'])
def add_data():

    # read request payload and unpack into separate variables
    numberA = int(request.json["numberA"])
    numberB = int(request.json["numberB"])

    # define the calculation result variable, based on the input variables
    calculationResult = numberA + numberB

    # return data in json format as response to our requester
    return jsonify({
        'result': str(calculationResult),
        'id': uuid.uuid4().hex})

# define the entry point of our application so that it can be imported by our main app script.
if __name__ == '__main__':
    app.run()